import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length and truncate if necessary
        int maxLength = 10;
        if (name.length() > maxLength) {
            name = name.substring(0, maxLength);
        }

        // Use StringBuilder to safely handle string concatenation
        StringBuilder greetingBuilder = new StringBuilder();
        greetingBuilder.append("Hello, ");
        greetingBuilder.append(name);

        System.out.println(greetingBuilder.toString());
    }
}

